def get_ayah(surah_name=None, surah_id=None, ayah_id=None):
    out = []
    for rec in q:
        if surah_name is not None and rec['surah_name'] != surah_name:
            continue
        if surah_id is not None and rec['surah_id'] != surah_id:
            continue
        if ayah_id is not None and rec['ayah_id'] != ayah_id:
            continue
        out.append(rec)
    return out

